import{_ as e,p as a,q as s,a1 as n}from"./framework-5866ffd3.js";const d={},l=n(`<h1 id="e2label" tabindex="-1"><a class="header-anchor" href="#e2label" aria-hidden="true">#</a> e2label</h1><p>设置第二扩展文件系统的卷标</p><h2 id="补充说明" tabindex="-1"><a class="header-anchor" href="#补充说明" aria-hidden="true">#</a> 补充说明</h2><p><strong>e2label命令</strong> 用来设置第二扩展文件系统的卷标。</p><h3 id="语法" tabindex="-1"><a class="header-anchor" href="#语法" aria-hidden="true">#</a> 语法</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>e2label<span class="token punctuation">(</span>参数<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="参数" tabindex="-1"><a class="header-anchor" href="#参数" aria-hidden="true">#</a> 参数</h3><ul><li>文件系统：指定文件系统所对应的设备文件名；</li><li>新卷标：为文件系统指定新卷标。</li></ul><h3 id="实例" tabindex="-1"><a class="header-anchor" href="#实例" aria-hidden="true">#</a> 实例</h3><p>许多用了多年Linux的人可能也没有用过e2label命令。但是这个命令相当有效。在介绍它之前,我们先看看<code>/etc/fstab文</code>件：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token assign-left variable">label</span><span class="token operator">=</span>//ext3 defaults <span class="token number">1</span> <span class="token number">1</span>
/dev/hda7 /usr ext3 defaults <span class="token number">1</span> <span class="token number">1</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>第二行的意思很容易懂，就是把<code>/dev/hda7</code> mount到<code>/usr</code>上。第一行没有指明分区，意思是把label(卷标)为/ 的分区mount到/上。这样写的好处在于即使如果把硬盘从主板上的ide0(hda) 换到ide2(hdc)上，系统仍然可以自动挂载正确的分区。通常Linux安装的时候已经自动指定了卷标。如果是手动增加的新分区，可以用下边的命令为 其指定卷标：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>e2label /dev/hdax /new
<span class="token function">mkdir</span> /new
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>然后在<code>/etc/fstab</code>里加入：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token assign-left variable">label</span><span class="token operator">=</span>/new  /new  ext3  defaults  <span class="token number">1</span> <span class="token number">1</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>下次重新起动机器的时候，就会把卷标为<code>/new</code>的分区挂接到<code>/new</code>上。</p>`,16),i=[l];function r(c,t){return a(),s("div",null,i)}const u=e(d,[["render",r],["__file","e2label.html.vue"]]);export{u as default};
